import { readFileSync } from "node:fs";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";
import { describe, expect, it } from "vitest";
import { listCommandCatalogNames, listCommandWrapperNames, renderAllCommandWrappers, } from "./commandWrappers.js";
import { ALL_FLOWS } from "./index.js";
function commandName(outputPath) {
    return outputPath.split("/").at(-1)?.replace(/\.ts$/, "") ?? "";
}
const FLOW_SOURCE_DIR = dirname(fileURLToPath(import.meta.url));
const PRODUCT_FLOW_FILES = ["assistant.ts", "setup.ts", "update.ts"];
describe("command wrapper generation", () => {
    it("keeps product flows catalog-backed instead of hand-writing command files", () => {
        for (const file of PRODUCT_FLOW_FILES) {
            const source = readFileSync(join(FLOW_SOURCE_DIR, file), "utf8");
            expect(source).toContain("BITFAB_PLUGIN_COMMANDS.defineCommands(");
            expect(source).not.toMatch(/\bfile:\s*["'][^"']+\.js["']/);
        }
    });
    it("keeps the command catalog and wrapper registry in lockstep", () => {
        expect(listCommandWrapperNames().sort()).toEqual(listCommandCatalogNames().sort());
    });
    it("covers every command declared by shared Bitfab flows", () => {
        const generatedNames = new Set(renderAllCommandWrappers()
            .filter((file) => file.target === "claude")
            .map((file) => commandName(file.outputPath)));
        const flowCommandNames = Object.values(ALL_FLOWS).flatMap((flow) => Object.values(flow.commands).map((command) => command.file.replace(/\.js$/, "")));
        expect(flowCommandNames).not.toHaveLength(0);
        for (const name of flowCommandNames) {
            expect(generatedNames).toContain(name);
        }
    });
    it("emits the same command wrapper surface for each editor plugin", () => {
        const rendered = renderAllCommandWrappers();
        const byTarget = {
            claude: rendered.filter((file) => file.target === "claude"),
            cursor: rendered.filter((file) => file.target === "cursor"),
            codex: rendered.filter((file) => file.target === "codex"),
        };
        const claudeNames = byTarget.claude.map((file) => commandName(file.outputPath));
        expect(claudeNames).not.toContain("commandSurface.test");
        expect(byTarget.cursor.map((file) => commandName(file.outputPath))).toEqual(claudeNames);
        expect(byTarget.codex.map((file) => commandName(file.outputPath))).toEqual(claudeNames);
    });
    it("preserves the Claude-only legacy update migration wrapper", () => {
        const rendered = renderAllCommandWrappers();
        const claudeUpdate = rendered.find((file) => file.target === "claude" && commandName(file.outputPath) === "update");
        const cursorUpdate = rendered.find((file) => file.target === "cursor" && commandName(file.outputPath) === "update");
        expect(claudeUpdate?.content).toContain("detectLegacyInstall");
        expect(cursorUpdate?.content).not.toContain("detectLegacyInstall");
    });
});
